mapper.select:
SELECT COUNT(*)
FROM favorite
WHERE user_id = #{userId}
  AND place_id = #{placeId}

mapper.delete:
DELETE FROM favorite
WHERE user_id = #{userId}
  AND place_id = #{placeId}

mapper.select:
SELECT COUNT(*) FROM place p JOIN restaurant rt ON p.place_id = rt.restaurant_id WHERE p.place_type = 'REST' AND rt.status = 'OPEN'
AND p.address LIKE '%' || #{region} || '%'
AND rt.category = #{category}
